import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { companyService, newsService } from '../services/api';

function DashboardPage() {
  const [companies, setCompanies] = useState([]);
  const [news, setNews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        // Fetch companies and news in parallel
        const [companiesResponse, newsResponse] = await Promise.all([
          companyService.getAllCompanies(),
          newsService.getLatestNews(5)
        ]);
        
        setCompanies(companiesResponse.data);
        setNews(newsResponse.data);
        setLoading(false);
      } catch (err) {
        console.error('Error fetching dashboard data:', err);
        setError('خطا در دریافت اطلاعات. لطفاً دوباره تلاش کنید.');
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center h-[300px]">
        <div className="w-10 h-10 border-4 border-gray-200 border-t-blue-500 rounded-full animate-spin mb-5"></div>
        <p className="text-gray-600">در حال بارگذاری...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="text-center py-12">
        <p className="text-red-600 text-xl mb-5">{error}</p>
        <button 
          className="btn btn-primary" 
          onClick={() => window.location.reload()}
        >
          تلاش مجدد
        </button>
      </div>
    );
  }

  return (
    <div className="py-8 rtl">
      <h1 className="text-3xl font-bold text-gray-800 mb-8">داشبورد</h1>
      
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2">
          <div className="bg-white rounded-lg shadow p-6 mb-8">
            <h2 className="text-xl font-bold text-gray-800 mb-5 pb-3 border-b border-gray-200">شرکت‌های بورسی</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
              {companies.map(company => (
                <Link 
                  key={company.id} 
                  to={`/companies/${company.id}`}
                  className="bg-gray-50 rounded-lg p-4 hover:-translate-y-1 hover:shadow-md transition duration-300 block"
                >
                  <h3 className="text-lg font-semibold text-gray-800 mb-2">{company.name}</h3>
                  <div className="inline-block bg-gray-200 text-gray-700 rounded px-3 py-1 text-sm">{company.symbol}</div>
                </Link>
              ))}
            </div>
          </div>
        </div>
        
        <div>
          <div className="bg-white rounded-lg shadow p-6">
            <h2 className="text-xl font-bold text-gray-800 mb-5 pb-3 border-b border-gray-200">آخرین اخبار</h2>
            <div>
              {news.length > 0 ? (
                news.map((item, index) => (
                  <div key={index} className="py-4 border-b border-gray-100 last:border-0">
                    <h3 className="text-lg font-semibold text-gray-800 mb-1">{item.title}</h3>
                    <p className="text-xs text-gray-500 mb-2">{item.date}</p>
                    <p className="text-gray-600 text-sm mb-2 line-clamp-3">{item.summary}</p>
                    {item.url && (
                      <a 
                        href={item.url} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="text-blue-500 text-sm hover:text-blue-700"
                      >
                        ادامه مطلب
                      </a>
                    )}
                  </div>
                ))
              ) : (
                <p className="text-gray-500 py-4">خبری یافت نشد.</p>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default DashboardPage;
